#!/bin/sh
# Generated by `losty new @@APP_NAME@@`
#
# Generates conf/nginx.conf for the given env and manages the nginx process.
#
# Usage:
#   ./run.sh [dev|prod]    generate config + start openresty  (default: dev)
#   ./run.sh -s reload     reload config without downtime
#   ./run.sh -s stop       stop immediately
#   ./run.sh -s quit       graceful stop

set -e
mkdir -p logs

RUN="openresty -p . -c conf/nginx.conf"

if [ "$1" = "-s" ]; then
    # passthrough:  ./run.sh -s reload|stop|quit
    $RUN -s "$2"
elif [ "$1" = "reload" ] || [ "$1" = "stop" ] || [ "$1" = "quit" ]; then
    # convenience short form:  ./run.sh reload
    $RUN -s "$1"
else
    ev="${1:-dev}"
    luajit gen.lua "$ev"
    $RUN
fi
